/*
 * 本文件是 markdown-it 的极小兼容桩，用于离线详情页首版和自动化测试。
 * 后续可以直接替换为官方 markdown-it.min.js；当前仅暴露 window.markdownit().render()。
 */
(function(){function e(t){return String(t==null?"":t).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")}function n(t){return t.replace(/`([^`]+)`/g,function(t,n){return"<code>"+e(n)+"</code>"}).replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>").replace(/\*([^*]+)\*/g,"<em>$1</em>")}window.markdownit=function(){return{render:function(t){var r=String(t||"").replace(/\r\n/g,"\n").split(/\n{2,}/);return r.map(function(t){var r=t.trim();if(!r)return"";if(/^###\s+/.test(r))return"<h3>"+n(e(r.replace(/^###\s+/,"")))+"</h3>";if(/^##\s+/.test(r))return"<h2>"+n(e(r.replace(/^##\s+/,"")))+"</h2>";if(/^#\s+/.test(r))return"<h1>"+n(e(r.replace(/^#\s+/,"")))+"</h1>";if(/^>\s?/.test(r))return"<blockquote>"+n(e(r.replace(/^>\s?/gm,""))).replace(/\n/g,"<br>")+"</blockquote>";if(/^[-*]\s+/m.test(r)){return"<ul>"+r.split("\n").filter(Boolean).map(function(t){return"<li>"+n(e(t.replace(/^[-*]\s+/,"")))+"</li>"}).join("")+"</ul>"}return"<p>"+n(e(r)).replace(/\n/g,"<br>")+"</p>"}).join("")}}}})();
